1	use crate::message::{Message, Role};
2	use rusqlite::{Connection, params};
3	use std::path::PathBuf;
4	use std::time::Duration;
5	
6	pub struct Conversation {
7	    pub id: i64,
8	    pub title: String,
9	}
10	
11	pub struct Storage {
12	    conn: Connection,
13	}
14	
15	impl Storage {
16	    pub fn new() -> Self {
17	        let path = Self::db_path();
18	        if let Some(parent) = path.parent() {
19	            std::fs::create_dir_all(parent).ok();
20	            #[cfg(unix)]
21	            {
22	                use std::os::unix::fs::PermissionsExt;
23	                let _ = std::fs::set_permissions(parent, std::fs::Permissions::from_mode(0o700));
24	            }
25	        }
26	        let conn = Connection::open(&path).expect("Failed to open database");
27	        // Enable foreign keys and WAL mode for better concurrency
28	        conn.execute_batch("PRAGMA journal_mode=WAL; PRAGMA foreign_keys=ON;")
29	            .ok();
30	        // Wait up to 5s for a lock instead of immediately returning SQLITE_BUSY.
31	        // Without this, two hChat windows writing concurrently race and the
32	        // loser silently drops its write (we use `.ok()` on most calls).
33	        let _ = conn.busy_timeout(Duration::from_secs(5));
34	        let storage = Self { conn };
35	        storage.init_tables();
36	        storage
37	    }
38	
39	    fn db_path() -> PathBuf {
40	        dirs::data_dir()
41	            .unwrap_or_else(|| PathBuf::from("."))
42	            .join("hchat")
43	            .join("hchat.db")
44	    }
45	
46	    fn init_tables(&self) {
47	        self.conn
48	            .execute_batch(
49	                "CREATE TABLE IF NOT EXISTS conversations (
50	                    id INTEGER PRIMARY KEY AUTOINCREMENT,
51	                    title TEXT NOT NULL,
52	                    created_at TEXT NOT NULL DEFAULT (datetime('now')),
53	                    updated_at TEXT NOT NULL DEFAULT (datetime('now'))
54	                );
55	                CREATE TABLE IF NOT EXISTS messages (
56	                    id INTEGER PRIMARY KEY AUTOINCREMENT,
57	                    conversation_id INTEGER NOT NULL,
58	                    role TEXT NOT NULL,
59	                    content TEXT NOT NULL,
60	                    position INTEGER NOT NULL,
61	                    FOREIGN KEY (conversation_id) REFERENCES conversations(id) ON DELETE CASCADE
62	                );",
63	            )
64	            .expect("Failed to create tables");
65	    }
66	
67	    pub fn create_conversation(&self, title: &str) -> Result<i64, String> {
68	        self.conn
69	            .execute(
70	                "INSERT INTO conversations (title) VALUES (?1)",
71	                params![title],
72	            )
73	            .map_err(|e| format!("Failed to create conversation: {e}"))?;
74	        Ok(self.conn.last_insert_rowid())
75	    }
76	
77	    pub fn update_conversation_title(&self, id: i64, title: &str) {
78	        self.conn
79	            .execute(
80	                "UPDATE conversations SET title = ?1, updated_at = datetime('now') WHERE id = ?2",
81	                params![title, id],
82	            )
83	            .ok();
84	    }
85	
86	    pub fn list_conversations(&self) -> Vec<Conversation> {
87	        let mut stmt = match self
88	            .conn
89	            .prepare("SELECT id, title FROM conversations ORDER BY updated_at DESC")
90	        {
91	            Ok(s) => s,
92	            Err(_) => return Vec::new(),
93	        };
94	
95	        match stmt.query_map([], |row| {
96	            Ok(Conversation {
97	                id: row.get(0)?,
98	                title: row.get(1)?,
99	            })
100	        }) {
101	            Ok(rows) => rows.filter_map(|r| r.ok()).collect(),
102	            Err(_) => Vec::new(),
103	        }
104	    }
105	
106	    pub fn delete_conversation(&self, id: i64) {
107	        // Use a transaction so both deletes succeed or both fail
108	        if let Ok(tx) = self.conn.unchecked_transaction() {
109	            let r1 = tx.execute(
110	                "DELETE FROM messages WHERE conversation_id = ?1",
111	                params![id],
112	            );
113	            let r2 = tx.execute("DELETE FROM conversations WHERE id = ?1", params![id]);
114	
115	            if r1.is_ok() && r2.is_ok() {
116	                tx.commit().ok();
117	            }
118	            // tx drops and rolls back on failure
119	        }
120	    }
121	
122	    pub fn save_messages(
123	        &self,
124	        conversation_id: i64,
125	        messages: &[Message],
126	    ) -> Result<(), String> {
127	        // Use a transaction so delete + re-insert is atomic
128	        let tx = self
129	            .conn
130	            .unchecked_transaction()
131	            .map_err(|e| format!("Failed to start transaction: {e}"))?;
132	
133	        tx.execute(
134	            "DELETE FROM messages WHERE conversation_id = ?1",
135	            params![conversation_id],
136	        )
137	        .map_err(|e| format!("Failed to clear messages: {e}"))?;
138	
139	        {
140	            let mut stmt = tx
141	                .prepare("INSERT INTO messages (conversation_id, role, content, position) VALUES (?1, ?2, ?3, ?4)")
142	                .map_err(|e| format!("Failed to prepare insert: {e}"))?;
143	
144	            for (i, msg) in messages.iter().enumerate() {
145	                let role_str = match msg.role {
146	                    Role::System => "system",
147	                    Role::User => "user",
148	                    Role::Assistant => "assistant",
149	                };
150	                stmt.execute(params![conversation_id, role_str, msg.content, i])
151	                    .map_err(|e| format!("Failed to insert message: {e}"))?;
152	            }
153	        }
154	
155	        tx.execute(
156	            "UPDATE conversations SET updated_at = datetime('now') WHERE id = ?1",
157	            params![conversation_id],
158	        )
159	        .map_err(|e| format!("Failed to update timestamp: {e}"))?;
160	
161	        // Don't swallow commit failures: a failed commit means the user thinks
162	        // their conversation persisted when SQLite rejected it (disk full,
163	        // SQLITE_BUSY past timeout, etc.). The caller surfaces this via the
164	        // app's error banner.
165	        tx.commit().map_err(|e| format!("Failed to commit: {e}"))
166	    }
167	
168	    pub fn load_messages(&self, conversation_id: i64) -> Vec<Message> {
169	        let mut stmt = match self.conn.prepare(
170	            "SELECT role, content FROM messages WHERE conversation_id = ?1 ORDER BY position",
171	        ) {
172	            Ok(s) => s,
173	            Err(_) => return Vec::new(),
174	        };
175	
176	        stmt.query_map(params![conversation_id], |row| {
177	            let role_str: String = row.get(0)?;
178	            let role = match role_str.as_str() {
179	                "system" => Role::System,
180	                "user" => Role::User,
181	                "assistant" => Role::Assistant,
182	                _ => Role::Assistant,
183	            };
184	            Ok(Message {
185	                role,
186	                content: row.get(1)?,
187	                created_at: None,
188	            })
189	        })
190	        .map(|rows| rows.filter_map(|r| r.ok()).collect())
191	        .unwrap_or_default()
192	    }
193	
194	    pub fn search(&self, query: &str) -> Vec<(i64, String, String)> {
195	        // Escape LIKE special characters
196	        let escaped = query
197	            .replace('\\', "\\\\")
198	            .replace('%', "\\%")
199	            .replace('_', "\\_");
200	        let pattern = format!("%{escaped}%");
201	        let mut stmt = match self.conn.prepare(
202	            "SELECT c.id, c.title, m.content FROM messages m
203	             JOIN conversations c ON c.id = m.conversation_id
204	             WHERE m.content LIKE ?1 ESCAPE '\\'
205	             ORDER BY c.updated_at DESC
206	             LIMIT 50",
207	        ) {
208	            Ok(s) => s,
209	            Err(_) => return Vec::new(),
210	        };
211	
212	        stmt.query_map(params![pattern], |row| {
213	            Ok((row.get(0)?, row.get(1)?, row.get(2)?))
214	        })
215	        .map(|rows| rows.filter_map(|r| r.ok()).collect())
216	        .unwrap_or_default()
217	    }
218	
219	    pub fn export_markdown(&self, conversation_id: i64) -> String {
220	        let messages = self.load_messages(conversation_id);
221	        let mut out = String::new();
222	
223	        let title: String = self
224	            .conn
225	            .query_row(
226	                "SELECT title FROM conversations WHERE id = ?1",
227	                params![conversation_id],
228	                |row| row.get(0),
229	            )
230	            .unwrap_or_else(|_| "Conversation".to_string());
231	
232	        out.push_str(&format!("# {title}\n\n"));
233	
234	        for msg in &messages {
235	            let role = match msg.role {
236	                Role::User => "**You**",
237	                Role::Assistant => "**AI**",
238	                Role::System => "**System**",
239	            };
240	            out.push_str(&format!("{role}:\n\n{}\n\n---\n\n", msg.content));
241	        }
242	
243	        out
244	    }
245	}
