148	        request = request
149	            .header("HTTP-Referer", "https://github.com/hhheath/hChat")
150	            .header("X-Title", "hChat");
151	    }
152	
153	    if let Ok(resp) = request.send().await {
154	        if resp.status().is_success() {
155	            if let Ok(openai_resp) = resp.json::<OpenAIModelsResponse>().await {
156	                let models: Vec<String> = openai_resp.data.into_iter().map(|m| m.id).collect();
