160	            }
161	        }
162	    }
163	
164	    // Fall back to Ollama /api/tags
165	    let api_base = url.trim_end_matches("/v1");
166	    let resp = client
167	        .get(format!("{api_base}/api/tags"))
168	        .send()
169	        .await
170	        .map_err(|e| format!("Failed to fetch models: {e}"))?;
