1	use crate::message::{Message, Role};
2	use rusqlite::{Connection, params};
3	use std::path::PathBuf;
4	use std::time::Duration;
5	
6	pub struct Conversation {
7	    pub id: i64,
8	    pub title: String,
9	}
10	
11	pub struct Storage {
12	    conn: Connection,
13	}
14	
15	impl Storage {
16	    pub fn new() -> Self {
17	        let path = Self::db_path();
18	        if let Some(parent) = path.parent() {
19	            std::fs::create_dir_all(parent).ok();
20	            #[cfg(unix)]
21	            {
22	                use std::os::unix::fs::PermissionsExt;
23	                let _ = std::fs::set_permissions(parent, std::fs::Permissions::from_mode(0o700));
24	            }
25	        }
26	        let conn = Connection::open(&path).expect("Failed to open database");
27	        // Enable foreign keys and WAL mode for better concurrency
28	        conn.execute_batch("PRAGMA journal_mode=WAL; PRAGMA foreign_keys=ON;")
29	            .ok();
30	        // Wait up to 5s for a lock instead of immediately returning SQLITE_BUSY.
31	        // Without this, two hChat windows writing concurrently race and the
32	        // loser silently drops its write (we use `.ok()` on most calls).
33	        let _ = conn.busy_timeout(Duration::from_secs(5));
34	        let storage = Self { conn };
35	        storage.init_tables();
36	        storage
37	    }
38	
39	    fn db_path() -> PathBuf {
40	        dirs::data_dir()
41	            .unwrap_or_else(|| PathBuf::from("."))
42	            .join("hchat")
43	            .join("hchat.db")
44	    }
45	
46	    fn init_tables(&self) {
47	        // schema_version is the migration cursor. Each migration runs at most
48	        // once; a fresh DB jumps straight to the latest version after the
49	        // initial CREATE block.
50	        self.conn
51	            .execute_batch(
52	                "CREATE TABLE IF NOT EXISTS schema_version (
53	                    version INTEGER PRIMARY KEY,
54	                    applied_at TEXT NOT NULL DEFAULT (datetime('now'))
55	                );
56	                CREATE TABLE IF NOT EXISTS conversations (
57	                    id INTEGER PRIMARY KEY AUTOINCREMENT,
58	                    title TEXT NOT NULL,
59	                    created_at TEXT NOT NULL DEFAULT (datetime('now')),
60	                    updated_at TEXT NOT NULL DEFAULT (datetime('now')),
61	                    model TEXT,
62	                    system_prompt TEXT,
63	                    temperature REAL,
64	                    max_tokens INTEGER,
65	                    use_max_tokens INTEGER NOT NULL DEFAULT 0,
66	                    top_p REAL,
67	                    frequency_penalty REAL,
68	                    presence_penalty REAL,
69	                    stop_sequences TEXT,
70	                    endpoint TEXT,
71	                    pinned INTEGER NOT NULL DEFAULT 0,
72	                    draft TEXT
73	                );
74	                CREATE TABLE IF NOT EXISTS messages (
75	                    id INTEGER PRIMARY KEY AUTOINCREMENT,
76	                    conversation_id INTEGER NOT NULL,
77	                    role TEXT NOT NULL,
78	                    content TEXT NOT NULL,
79	                    position INTEGER NOT NULL,
80	                    parent_id INTEGER REFERENCES messages(id) ON DELETE CASCADE,
81	                    branch_index INTEGER NOT NULL DEFAULT 0,
82	                    created_at INTEGER,
83	                    FOREIGN KEY (conversation_id) REFERENCES conversations(id) ON DELETE CASCADE
84	                );
85	                CREATE TABLE IF NOT EXISTS presets (
86	                    id INTEGER PRIMARY KEY AUTOINCREMENT,
87	                    name TEXT NOT NULL,
88	                    model TEXT,
89	                    system_prompt TEXT,
90	                    temperature REAL,
91	                    max_tokens INTEGER,
92	                    use_max_tokens INTEGER NOT NULL DEFAULT 0,
93	                    top_p REAL,
94	                    frequency_penalty REAL,
95	                    presence_penalty REAL,
96	                    stop_sequences TEXT,
97	                    endpoint TEXT,
98	                    created_at TEXT NOT NULL DEFAULT (datetime('now'))
99	                );
100	                CREATE INDEX IF NOT EXISTS idx_messages_conv_position ON messages(conversation_id, position);
101	                CREATE INDEX IF NOT EXISTS idx_messages_parent ON messages(parent_id);
102	                CREATE INDEX IF NOT EXISTS idx_conversations_pinned_updated ON conversations(pinned DESC, updated_at DESC);
103	                INSERT OR IGNORE INTO schema_version (version) VALUES (2);",
104	            )
105	            .expect("Failed to create tables");
106	    }
107	
108	    /// Current schema version, or 0 if the table is empty/missing.
109	    #[allow(dead_code)]
110	    fn schema_version(&self) -> i64 {
111	        self.conn
112	            .query_row(
113	                "SELECT COALESCE(MAX(version), 0) FROM schema_version",
114	                [],
115	                |row| row.get(0),
116	            )
117	            .unwrap_or(0)
118	    }
119	
120	    pub fn create_conversation(&self, title: &str) -> Result<i64, String> {
121	        self.conn
122	            .execute(
123	                "INSERT INTO conversations (title) VALUES (?1)",
124	                params![title],
125	            )
126	            .map_err(|e| format!("Failed to create conversation: {e}"))?;
127	        Ok(self.conn.last_insert_rowid())
128	    }
129	
130	    pub fn update_conversation_title(&self, id: i64, title: &str) {
131	        self.conn
132	            .execute(
133	                "UPDATE conversations SET title = ?1, updated_at = datetime('now') WHERE id = ?2",
134	                params![title, id],
135	            )
136	            .ok();
137	    }
138	
139	    pub fn list_conversations(&self) -> Vec<Conversation> {
140	        let mut stmt = match self
141	            .conn
142	            .prepare("SELECT id, title FROM conversations ORDER BY updated_at DESC")
143	        {
144	            Ok(s) => s,
145	            Err(_) => return Vec::new(),
146	        };
147	
148	        match stmt.query_map([], |row| {
149	            Ok(Conversation {
150	                id: row.get(0)?,
151	                title: row.get(1)?,
152	            })
153	        }) {
154	            Ok(rows) => rows.filter_map(|r| r.ok()).collect(),
155	            Err(_) => Vec::new(),
156	        }
157	    }
158	
159	    pub fn delete_conversation(&self, id: i64) {
160	        // Use a transaction so both deletes succeed or both fail
161	        if let Ok(tx) = self.conn.unchecked_transaction() {
162	            let r1 = tx.execute(
163	                "DELETE FROM messages WHERE conversation_id = ?1",
164	                params![id],
165	            );
166	            let r2 = tx.execute("DELETE FROM conversations WHERE id = ?1", params![id]);
167	
168	            if r1.is_ok() && r2.is_ok() {
169	                tx.commit().ok();
170	            }
171	            // tx drops and rolls back on failure
172	        }
173	    }
174	
175	    pub fn save_messages(
176	        &self,
177	        conversation_id: i64,
178	        messages: &[Message],
179	    ) -> Result<(), String> {
180	        // Use a transaction so delete + re-insert is atomic
181	        let tx = self
182	            .conn
183	            .unchecked_transaction()
184	            .map_err(|e| format!("Failed to start transaction: {e}"))?;
185	
186	        tx.execute(
187	            "DELETE FROM messages WHERE conversation_id = ?1",
188	            params![conversation_id],
189	        )
190	        .map_err(|e| format!("Failed to clear messages: {e}"))?;
191	
192	        {
193	            let mut stmt = tx
194	                .prepare("INSERT INTO messages (conversation_id, role, content, position) VALUES (?1, ?2, ?3, ?4)")
195	                .map_err(|e| format!("Failed to prepare insert: {e}"))?;
196	
197	            for (i, msg) in messages.iter().enumerate() {
198	                let role_str = match msg.role {
199	                    Role::System => "system",
200	                    Role::User => "user",
201	                    Role::Assistant => "assistant",
202	                };
203	                stmt.execute(params![conversation_id, role_str, msg.content, i])
204	                    .map_err(|e| format!("Failed to insert message: {e}"))?;
205	            }
206	        }
207	
208	        tx.execute(
209	            "UPDATE conversations SET updated_at = datetime('now') WHERE id = ?1",
210	            params![conversation_id],
211	        )
212	        .map_err(|e| format!("Failed to update timestamp: {e}"))?;
213	
214	        // Don't swallow commit failures: a failed commit means the user thinks
215	        // their conversation persisted when SQLite rejected it (disk full,
216	        // SQLITE_BUSY past timeout, etc.). The caller surfaces this via the
217	        // app's error banner.
218	        tx.commit().map_err(|e| format!("Failed to commit: {e}"))
219	    }
220	
221	    pub fn load_messages(&self, conversation_id: i64) -> Vec<Message> {
222	        let mut stmt = match self.conn.prepare(
223	            "SELECT role, content FROM messages WHERE conversation_id = ?1 ORDER BY position",
224	        ) {
225	            Ok(s) => s,
226	            Err(_) => return Vec::new(),
227	        };
228	
229	        stmt.query_map(params![conversation_id], |row| {
230	            let role_str: String = row.get(0)?;
231	            let role = match role_str.as_str() {
232	                "system" => Role::System,
233	                "user" => Role::User,
234	                "assistant" => Role::Assistant,
235	                _ => Role::Assistant,
236	            };
237	            Ok(Message {
238	                role,
239	                content: row.get(1)?,
240	                created_at: None,
241	            })
242	        })
243	        .map(|rows| rows.filter_map(|r| r.ok()).collect())
244	        .unwrap_or_default()
245	    }
246	
247	    pub fn search(&self, query: &str) -> Vec<(i64, String, String)> {
248	        // Escape LIKE special characters
249	        let escaped = query
250	            .replace('\\', "\\\\")
251	            .replace('%', "\\%")
252	            .replace('_', "\\_");
253	        let pattern = format!("%{escaped}%");
254	        let mut stmt = match self.conn.prepare(
255	            "SELECT c.id, c.title, m.content FROM messages m
256	             JOIN conversations c ON c.id = m.conversation_id
257	             WHERE m.content LIKE ?1 ESCAPE '\\'
258	             ORDER BY c.updated_at DESC
259	             LIMIT 50",
260	        ) {
261	            Ok(s) => s,
262	            Err(_) => return Vec::new(),
263	        };
264	
265	        stmt.query_map(params![pattern], |row| {
266	            Ok((row.get(0)?, row.get(1)?, row.get(2)?))
267	        })
268	        .map(|rows| rows.filter_map(|r| r.ok()).collect())
269	        .unwrap_or_default()
270	    }
